(25, 0, 'Khoa Phòng chống bệnh truyền nhiễm', 'Khoa-Phong-chong-benh-truyen-nhiem', '', '', 5, 5, 0, '', 0, 1, 1547007379, 1655953643, 'Tầng 5, Tòa nhà Trung tâm Kiểm soát bệnh tật - 118 Lê Đình Lý, Thanh Khê, Đà Nẵng', 'pcbtncdcdng@gmail.com', '0236.3890.412', '', '', '', 2, '', 1), 
(22, 0, 'Phòng Kế hoạch - Nghiệp vụ', 'Phong-Ke-hoach-Nghiep-vu', '', '', 3, 3, 0, '', 0, 1, 1506648501, 1738827717, 'Tầng 4, Tòa nhà Trung tâm Kiểm soát bệnh tật - 118 Lê Đình Lý, Thanh Khê, Đà Nẵng', 'khnvcdcdng@gmail.com', '0236.3890.410', '', '', '', 3, '<p><span style=\"font-size:11pt\"><span style=\"line-height:150%\"><span style=\"font-family:Calibri,sans-serif\"><b><span style=\"font-size:13.5pt\"><span style=\"line-height:150%\"><span style=\"font-family:&#039;Times New Roman&#039;,serif\">1. CƠ CẤU TỔ CHỨC</span></span></span></b><br  />
